// MobileServiceServer is the server API for MobileService service.
// All implementations should embed UnimplementedMobileServiceServer
// for forward compatibility.
//
// MobileService is the authenticated post-pairing API.
//
// Conventions:
//   - Every multi-environment RPC carries `environment_id`. "0" means the
//     local Docker environment.
//   - Inspection / details responses use `bytes details_json` carrying the
//     same JSON shape as the REST endpoint so existing Swift Codable types
//     decode them unchanged. Lists/summaries/native types are fully typed.
//   - Mutating actions return ActionResult unless they need richer output.
type MobileServiceServer interface {
	// ---------- Pairing-related ----------
	GetCurrentDevice(context.Context, *GetCurrentDeviceRequest) (*GetCurrentDeviceResponse, error)
	RevokeCurrentDevice(context.Context, *RevokeCurrentDeviceRequest) (*RevokeCurrentDeviceResponse, error)
	// ---------- Server / system ----------
	GetServerInfo(context.Context, *GetServerInfoRequest) (*GetServerInfoResponse, error)
	GetDockerInfo(context.Context, *GetDockerInfoRequest) (*GetDockerInfoResponse, error)
	GetAppVersion(context.Context, *GetAppVersionRequest) (*GetAppVersionResponse, error)
	// ---------- Containers ----------
	ListContainers(context.Context, *ListContainersRequest) (*ListContainersResponse, error)
	InspectContainer(context.Context, *InspectContainerRequest) (*InspectContainerResponse, error)
	StartContainer(context.Context, *ContainerActionRequest) (*ActionResult, error)
	StopContainer(context.Context, *ContainerActionRequest) (*ActionResult, error)
	RestartContainer(context.Context, *ContainerActionRequest) (*ActionResult, error)
	RedeployContainer(context.Context, *ContainerActionRequest) (*ActionResult, error)
	DeleteContainer(context.Context, *DeleteContainerRequest) (*ActionResult, error)
	PruneContainers(context.Context, *PruneContainersRequest) (*PruneResult, error)
	// ---------- Volumes ----------
	ListVolumes(context.Context, *ListVolumesRequest) (*ListVolumesResponse, error)
	GetVolumeSizes(context.Context, *GetVolumeSizesRequest) (*GetVolumeSizesResponse, error)
	CreateVolume(context.Context, *CreateVolumeRequest) (*CreateVolumeResponse, error)
	DeleteVolume(context.Context, *DeleteVolumeRequest) (*ActionResult, error)
	PruneVolumes(context.Context, *PruneVolumesRequest) (*PruneResult, error)
	// ---------- Networks ----------
	ListNetworks(context.Context, *ListNetworksRequest) (*ListNetworksResponse, error)
	CreateNetwork(context.Context, *CreateNetworkRequest) (*CreateNetworkResponse, error)
	DeleteNetwork(context.Context, *DeleteNetworkRequest) (*ActionResult, error)
	PruneNetworks(context.Context, *PruneNetworksRequest) (*PruneResult, error)
	// ---------- Container extras ----------
	PauseContainer(context.Context, *ContainerActionRequest) (*ActionResult, error)
	UnpauseContainer(context.Context, *ContainerActionRequest) (*ActionResult, error)
	KillContainer(context.Context, *ContainerActionRequest) (*ActionResult, error)
	RenameContainer(context.Context, *RenameContainerRequest) (*ActionResult, error)
	// ---------- Images ----------
	ListImages(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	InspectImage(context.Context, *EnvIDAndIDRequest) (*JSONResponse, error)
	DeleteImage(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	PruneImages(context.Context, *EnvIDOnlyRequest) (*PruneResult, error)
	// ---------- Image updates ----------
	GetImageUpdateSummary(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	GetImageUpdatesByRefs(context.Context, *GetImageUpdatesByRefsRequest) (*JSONResponse, error)
	CheckImageUpdates(context.Context, *EnvIDAndQueryRequest) (*JSONResponse, error)
	CheckAllImageUpdates(context.Context, *EnvIDOnlyRequest) (*ActionResult, error)
	CheckImageUpdate(context.Context, *EnvIDAndIDRequest) (*JSONResponse, error)
	// ---------- Vulnerabilities ----------
	GetVulnerabilityScannerStatus(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	GetImageVulnerabilitySummary(context.Context, *EnvIDAndIDRequest) (*JSONResponse, error)
	ListImageVulnerabilities(context.Context, *EnvIDAndIDAndQueryRequest) (*JSONResponse, error)
	ScanImageVulnerabilities(context.Context, *EnvIDAndIDRequest) (*JSONResponse, error)
	GetAllVulnerabilitiesSummary(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	GetVulnerabilityImageOptions(context.Context, *EnvIDAndQueryRequest) (*JSONResponse, error)
	ListAllVulnerabilities(context.Context, *EnvIDAndQueryRequest) (*JSONResponse, error)
	IgnoreVulnerability(context.Context, *EnvIDAndJSONBodyRequest) (*JSONResponse, error)
	DeleteVulnerabilityIgnore(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	// ---------- Projects (read + mutations) ----------
	ListProjects(context.Context, *ListProjectsRequest) (*ListProjectsResponse, error)
	GetProject(context.Context, *GetProjectRequest) (*GetProjectResponse, error)
	CreateProject(context.Context, *EnvIDAndJSONBodyRequest) (*JSONResponse, error)
	UpdateProject(context.Context, *EnvIDAndIDAndJSONBodyRequest) (*JSONResponse, error)
	DeleteProject(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	StartProject(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	StopProject(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	DestroyProject(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	// ---------- Environments ----------
	ListEnvironments(context.Context, *EmptyRequest) (*JSONResponse, error)
	CreateEnvironment(context.Context, *JSONBodyRequest) (*JSONResponse, error)
	TestEnvironment(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	// ---------- Settings ----------
	GetSettings(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	UpdateSettings(context.Context, *EnvIDAndJSONBodyRequest) (*JSONResponse, error)
	GetOidcStatus(context.Context, *EmptyRequest) (*JSONResponse, error)
	// ---------- Notifications ----------
	GetNotificationSettings(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	SaveNotificationProvider(context.Context, *EnvIDAndJSONBodyRequest) (*JSONResponse, error)
	DeleteNotificationProvider(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	TestNotificationProvider(context.Context, *EnvIDAndIDAndJSONBodyRequest) (*ActionResult, error)
	GetApprise(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	UpdateApprise(context.Context, *EnvIDAndJSONBodyRequest) (*JSONResponse, error)
	TestApprise(context.Context, *EnvIDAndJSONBodyRequest) (*ActionResult, error)
	// ---------- Webhooks ----------
	ListWebhooks(context.Context, *EnvIDOnlyRequest) (*JSONResponse, error)
	CreateWebhook(context.Context, *EnvIDAndJSONBodyRequest) (*JSONResponse, error)
	UpdateWebhook(context.Context, *EnvIDAndIDAndJSONBodyRequest) (*JSONResponse, error)
	DeleteWebhook(context.Context, *EnvIDAndIDRequest) (*ActionResult, error)
	// ---------- Users (global) ----------
	ListUsers(context.Context, *EmptyRequest) (*JSONResponse, error)
	CreateUser(context.Context, *JSONBodyRequest) (*JSONResponse, error)
	UpdateUser(context.Context, *IDAndJSONBodyRequest) (*JSONResponse, error)
	DeleteUser(context.Context, *IDOnlyRequest) (*ActionResult, error)
	// ---------- API keys (global) ----------
	ListApiKeys(context.Context, *EmptyRequest) (*JSONResponse, error)
	CreateApiKey(context.Context, *JSONBodyRequest) (*JSONResponse, error)
	DeleteApiKey(context.Context, *IDOnlyRequest) (*ActionResult, error)
	// ---------- Container registries (global) ----------
	ListContainerRegistries(context.Context, *EmptyRequest) (*JSONResponse, error)
	CreateContainerRegistry(context.Context, *JSONBodyRequest) (*JSONResponse, error)
	UpdateContainerRegistry(context.Context, *IDAndJSONBodyRequest) (*JSONResponse, error)
	DeleteContainerRegistry(context.Context, *IDOnlyRequest) (*ActionResult, error)
	// ---------- Templates (global) ----------
	ListTemplates(context.Context, *EmptyRequest) (*JSONResponse, error)
	GetTemplateContent(context.Context, *IDOnlyRequest) (*JSONResponse, error)
	ListTemplateRegistries(context.Context, *EmptyRequest) (*JSONResponse, error)
	CreateTemplateRegistry(context.Context, *JSONBodyRequest) (*JSONResponse, error)
	UpdateTemplateRegistry(context.Context, *IDAndJSONBodyRequest) (*JSONResponse, error)
	DeleteTemplateRegistry(context.Context, *IDOnlyRequest) (*ActionResult, error)
	// ---------- System ----------
	PruneSystem(context.Context, *EnvIDAndJSONBodyRequest) (*JSONResponse, error)
	// ---------- Streaming ----------
	StreamContainerLogs(*StreamContainerLogsRequest, grpc.ServerStreamingServer[StreamFrame]) error
	StreamContainerStats(*EnvIDAndIDRequest, grpc.ServerStreamingServer[StreamFrame]) error
	StreamProjectLogs(*StreamProjectLogsRequest, grpc.ServerStreamingServer[StreamFrame]) error
	StreamSystemStats(*StreamSystemStatsRequest, grpc.ServerStreamingServer[StreamFrame]) error
	StreamPullImage(*PullImageRequest, grpc.ServerStreamingServer[StreamFrame]) error
	ContainerTerminal(grpc.BidiStreamingServer[TerminalClientFrame, TerminalServerFrame]) error
}

